const source = $input.first()?.json ?? {};
const query = source.query ?? source;
const headers = source.headers ?? {};
const clean = (value) => value === null || value === undefined ? '' : String(value).trim();
const deriveBaseUrl = (headers, fallback) => {
  const forwardedProto = clean(headers['x-forwarded-proto']);
  const forwardedHost = clean(headers['x-forwarded-host']);
  const host = forwardedHost || clean(headers.host);
  const forwardedPort = clean(headers['x-forwarded-port']);
  if (!host) return fallback;
  const proto = forwardedProto || 'http';
  let authority = host;
  if (forwardedPort && !authority.includes(':')) {
    const isDefaultPort = (proto === 'http' && forwardedPort === '80') || (proto === 'https' && forwardedPort === '443');
    if (!isDefaultPort) authority = `${authority}:${forwardedPort}`;
  }
  return `${proto}://${authority}`;
};
const sqlLiteral = (value) => `'${String(value).replace(/'/g, "''")}'`;
const rawBatchId = clean(query.batch_id ?? query.batchId);
const parsedBatchId = Number.parseInt(rawBatchId, 10);
const rawStartRow = clean(query.start_row ?? query.startRow);
const rawStartCol = clean(query.start_col ?? query.startCol);
const parsedStartRow = Number.parseInt(rawStartRow, 10);
const parsedStartCol = Number.parseInt(rawStartCol, 10);
const startRow = Number.isInteger(parsedStartRow) && parsedStartRow >= 1 && parsedStartRow <= 7 ? parsedStartRow : 1;
const startCol = Number.isInteger(parsedStartCol) && parsedStartCol >= 1 && parsedStartCol <= 3 ? parsedStartCol : 1;
const fallbackBaseUrl = 'http://n8n:5678';
const n8nBaseUrl = deriveBaseUrl(headers, fallbackBaseUrl);
if (!Number.isInteger(parsedBatchId) || parsedBatchId <= 0) {
  return [{
    json: {
      batch_id: rawBatchId,
      start_row: startRow,
      start_col: startCol,
      response_code: 400,
      n8n_base_url: n8nBaseUrl,
      sql: "SELECT NULL::bigint AS batch_id, NULL::text AS status, NULL::timestamptz AS created_at, NULL::timestamptz AS completed_at, NULL::boolean AS no_address_email_sent, 0::bigint AS signup_row_count, 0::bigint AS manual_row_count, 0::bigint AS member_row_count, 0::bigint AS regular_tags, 0::bigint AS parent_tags, 0::bigint AS keys, 0::bigint AS total_items, 0::bigint AS no_address_email_count;"
    }
  }];
}
const sql = `
WITH batch_base AS (
  SELECT b.id, b.status, b.created_at, b.completed_at, b.no_address_email_sent
  FROM public.signup_batches b
  WHERE b.id = ${sqlLiteral(parsedBatchId)}::bigint
),
summary AS (
  SELECT *
  FROM public.vw_signup_batches_summary
  WHERE batch_id = ${sqlLiteral(parsedBatchId)}::bigint
),
payer_items AS (
  SELECT
    i.batch_id,
    i.payer,
    MAX(NULLIF(TRIM(i.email_address), '')) AS email_address,
    MAX(NULLIF(TRIM(i.address_1), '')) AS address_1,
    MAX(NULLIF(TRIM(i.address_2), '')) AS address_2,
    MAX(NULLIF(TRIM(i.address_3), '')) AS address_3,
    MAX(NULLIF(TRIM(i.town), '')) AS town,
    MAX(NULLIF(TRIM(i.postcode), '')) AS postcode,
    COALESCE(SUM(i.parent_tags), 0)::int AS parent_tags,
    COALESCE(SUM(i.regular_tags), 0)::int AS regular_tags,
    COALESCE(SUM(i.key_tags), 0)::int AS keys,
    COALESCE(SUM(i.regular_tags + i.parent_tags + i.key_tags), 0)::int AS total_items
  FROM public.vw_signup_batch_items i
  WHERE i.batch_id = ${sqlLiteral(parsedBatchId)}::bigint
    AND COALESCE(i.product, '') <> 'a. Social 2026'
  GROUP BY i.batch_id, i.payer
),
best_member AS (
  SELECT DISTINCT ON (CONCAT(rm."First name", ' ', rm."Last name"))
    CONCAT(rm."First name", ' ', rm."Last name") AS payer_name,
    rm."First name" AS first_name,
    rm."Last name" AS last_name,
    NULLIF(TRIM(rm."Email address"), '') AS email_address
  FROM public.raw_members rm
  WHERE COALESCE(rm.is_current, true) = true
  ORDER BY CONCAT(rm."First name", ' ', rm."Last name"),
           CASE WHEN NULLIF(TRIM(rm."Email address"), '') IS NOT NULL THEN 0 ELSE 1 END,
           CASE WHEN COALESCE(NULLIF(TRIM(rm."Status"), ''), '') = 'Active' THEN 0 ELSE 1 END
),
no_address_recipients AS (
  SELECT p.payer
  FROM payer_items p
  LEFT JOIN LATERAL public.resolve_best_contact_row(
    p.payer,
    p.email_address,
    NULLIF(regexp_replace(p.payer, '^\\S+\\s*', ''), ''),
    false
  ) bc ON TRUE
  LEFT JOIN best_member bm
    ON p.payer = bm.payer_name
  WHERE COALESCE(NULLIF(TRIM(bc.email_address), ''), p.email_address, bm.email_address) IS NOT NULL
    AND (
      NULLIF(TRIM(COALESCE(NULLIF(TRIM(bc.address_1), ''), p.address_1)), '') IS NULL
      OR NULLIF(TRIM(COALESCE(NULLIF(TRIM(bc.postcode), ''), p.postcode)), '') IS NULL
    )
)
SELECT
  b.id AS batch_id,
  b.status,
  b.created_at,
  b.completed_at,
  b.no_address_email_sent,
  COALESCE(s.signup_rows, 0) AS signup_row_count,
  COALESCE(s.manual_rows, 0) AS manual_row_count,
  COALESCE(s.signup_rows, 0) + COALESCE(s.manual_rows, 0) AS member_row_count,
  COALESCE(s.regular_tags, 0) AS regular_tags,
  COALESCE(s.parent_tags, 0) AS parent_tags,
  COALESCE(s.key_tags, 0) AS keys,
  COALESCE(s.total_items, 0) AS total_items,
  COALESCE((SELECT COUNT(*) FROM no_address_recipients), 0) AS no_address_email_count
FROM batch_base b
LEFT JOIN summary s
  ON s.batch_id = b.id
LIMIT 1;`;
return [{ json: { batch_id: parsedBatchId, start_row: startRow, start_col: startCol, response_code: 200, n8n_base_url: n8nBaseUrl, sql } }];

const source = $('Build Batch Query').first()?.json ?? {};
const row = $input.first()?.json ?? {};
const clean = (value) => value === null || value === undefined ? '' : String(value).trim();
const escapeHtml = (value) => clean(value)
  .replace(/&/g, '&amp;')
  .replace(/</g, '&lt;')
  .replace(/>/g, '&gt;')
  .replace(/\"/g, '&quot;')
  .replace(/'/g, '&#39;');
const batchId = clean(row.batch_id || source.batch_id);
const hasBatch = clean(row.batch_id) !== '';
const status = clean(row.status);
const createdAt = clean(row.created_at);
const completedAt = clean(row.completed_at);
const n8nBaseUrl = clean(source.n8n_base_url) || 'http://n8n:5678';
const startRow = Number.parseInt(clean(source.start_row), 10);
const startCol = Number.parseInt(clean(source.start_col), 10);
const labelStartRow = Number.isInteger(startRow) && startRow >= 1 && startRow <= 7 ? startRow : 1;
const labelStartCol = Number.isInteger(startCol) && startCol >= 1 && startCol <= 3 ? startCol : 1;
const noAddressEmailSent = row.no_address_email_sent === true || clean(row.no_address_email_sent).toLowerCase() === 'true';
const noAddressEmailCount = Number.parseInt(clean(row.no_address_email_count), 10) || 0;
const recipientLabel = `${noAddressEmailCount} ${noAddressEmailCount === 1 ? 'recipient' : 'recipients'}`;
const noAddressEmailStatus = noAddressEmailSent
  ? `Sent (${recipientLabel})`
  : status === 'Complete'
    ? `Ready to send (${recipientLabel})`
    : status
      ? `Unavailable while ${status} (${recipientLabel})`
      : `Unavailable (${recipientLabel})`;
const summaryCards = [
  { label: 'Status', value: status || 'Unknown' },
  { label: 'Created', value: createdAt || 'Not available' },
  { label: 'Completed', value: completedAt || 'Not available' },
  { label: 'No Address Emails', value: noAddressEmailStatus },
  { label: 'Rows', value: String(row.member_row_count ?? 0) },
  { label: 'Shoe Tags', value: String(row.regular_tags ?? 0) },
  { label: 'Parents', value: String(row.parent_tags ?? 0) },
  { label: 'Keys', value: String(row.keys ?? 0) },
  { label: 'Total Items', value: String(row.total_items ?? 0) },
];
const labelsBaseUrl = `${n8nBaseUrl}/webhook/download-j8160-labels`;
const envelopesUrl = `${n8nBaseUrl}/webhook/download-dl-envelopes?batch_id=${encodeURIComponent(batchId)}`;
const emailsUrl = `${n8nBaseUrl}/webhook/send-no-address-batch-emails?batch_id=${encodeURIComponent(batchId)}`;
const rowOptions = Array.from({ length: 7 }, (_, index) => {
  const value = index + 1;
  return `<option value="${value}"${value === labelStartRow ? ' selected' : ''}>Row ${value}</option>`;
}).join('');
const colOptions = Array.from({ length: 3 }, (_, index) => {
  const value = index + 1;
  return `<option value="${value}"${value === labelStartCol ? ' selected' : ''}>Col ${value}</option>`;
}).join('');
const labelsCard = hasBatch ? `
  <form class="action-card action-labels action-form" action="${labelsBaseUrl}" method="get">
    <input type="hidden" name="batch_id" value="${escapeHtml(batchId)}">
    <strong>🏷️ Labels</strong>
    <span>Generate the current J8160 labels PDF for this batch. Start position applies to page 1 only.</span>
    <div class="form-grid">
      <label class="select-label">Start row<select name="start_row">${rowOptions}</select></label>
      <label class="select-label">Start col<select name="start_col">${colOptions}</select></label>
    </div>
    <button type="submit" class="inline-action">Generate Labels</button>
  </form>` : '';
let emailButton = `<div class="disabled-card"><strong>No Address Emails</strong><span>Available only when the batch is complete and not already sent. ${escapeHtml(recipientLabel)} currently match the no-address rule.</span></div>`;
if (hasBatch && status === 'Complete' && !noAddressEmailSent) {
  emailButton = `<a class="action-card action-email" href="${emailsUrl}"><strong>📨 No Address Emails</strong><span>Send personalized no-address emails to ${escapeHtml(recipientLabel)} for this batch.</span></a>`;
} else if (hasBatch && status === 'Complete' && noAddressEmailSent) {
  emailButton = `<div class="disabled-card"><strong>No Address Emails</strong><span>Already sent for this batch. ${escapeHtml(recipientLabel)} currently match the no-address rule.</span></div>`;
} else if (hasBatch && status) {
  emailButton = `<div class="disabled-card"><strong>No Address Emails</strong><span>Batch status is ${escapeHtml(status)}. ${escapeHtml(recipientLabel)} currently match the no-address rule, but emails can only be sent when Complete.</span></div>`;
}
const body = hasBatch ? `
  <section class="hero">
    <h1>Batch ${escapeHtml(batchId)} Actions</h1>
    <p class="lede">Run label, envelope, or email actions for this batch from one page.</p>
    <div class="summary">${summaryCards.map((card) => `<div class="summary-card"><h2>${escapeHtml(card.label)}</h2><p>${escapeHtml(card.value)}</p></div>`).join('')}</div>
    <div class="actions">
      ${labelsCard}
      <a class="action-card action-envelopes" href="${envelopesUrl}"><strong>✉️ Envelopes</strong><span>Generate the current DL envelopes PDF for this batch.</span></a>
      ${emailButton}
    </div>
    <div class="footer-actions">
      <button type="button" class="close-button" onclick="window.close()">Close</button>
    </div>
  </section>` : `
  <section class="hero">
    <h1>Batch Actions</h1>
    <p class="lede">The batch could not be resolved from the request.</p>
    <div class="disabled-card"><strong>Missing or invalid batch ID</strong><span>Use the action link from the Signup Batches card so the batch ID is provided automatically.</span></div>
    <div class="footer-actions">
      <button type="button" class="close-button" onclick="window.close()">Close</button>
    </div>
  </section>`;
const html = `<!doctype html>
<html lang="en">
<head>
  <meta charset="utf-8">
  <meta name="viewport" content="width=device-width, initial-scale=1">
  <title>${hasBatch ? `Batch ${escapeHtml(batchId)} Actions` : 'Batch Actions'}</title>
  <style>
    :root {
      color-scheme: light;
      --bg: #f7f8fc;
      --panel: #ffffff;
      --ink: #2e3d4e;
      --muted: #6b7785;
      --line: #e2e8f0;
      --accent: #509ee3;
      --accent-dark: #2f80d8;
      --soft: #f2f7fd;
      --labels: #edf5ff;
      --envelopes: #f4f2ff;
      --email: #f2f7fd;
      --button-soft: #eef2f7;
    }
    * { box-sizing: border-box; }
    body {
      margin: 0;
      font-family: Lato, 'Helvetica Neue', Arial, sans-serif;
      color: var(--ink);
      background: linear-gradient(180deg, #fbfcfe 0%, var(--bg) 100%);
      padding: 24px;
    }
    .wrap {
      max-width: 960px;
      margin: 0 auto;
      display: grid;
      gap: 20px;
    }
    .hero {
      background: var(--panel);
      border: 1px solid var(--line);
      border-radius: 18px;
      padding: 28px;
      box-shadow: 0 18px 40px rgba(53, 72, 91, 0.08);
    }
    h1 {
      margin: 0 0 6px;
      font-size: 34px;
      line-height: 1.05;
      letter-spacing: -0.02em;
    }
    .lede {
      margin: 0;
      color: var(--muted);
      font-size: 16px;
    }
    .summary {
      display: grid;
      gap: 14px;
      grid-template-columns: repeat(auto-fit, minmax(180px, 1fr));
      margin-top: 22px;
      margin-bottom: 22px;
    }
    .summary-card {
      border: 1px solid var(--line);
      border-radius: 14px;
      padding: 16px;
      background: var(--soft);
    }
    .summary-card h2 {
      margin: 0 0 8px;
      font-size: 14px;
      text-transform: uppercase;
      letter-spacing: 0.08em;
      color: var(--muted);
    }
    .summary-card p {
      margin: 0;
      font-size: 18px;
      line-height: 1.4;
    }
    .actions {
      display: grid;
      gap: 14px;
      grid-template-columns: repeat(auto-fit, minmax(220px, 1fr));
    }
    .action-card,
    .disabled-card {
      border-radius: 16px;
      border: 1px solid var(--line);
      padding: 18px;
      min-height: 170px;
      display: flex;
      flex-direction: column;
      justify-content: space-between;
      text-decoration: none;
      color: var(--ink);
      box-shadow: 0 10px 24px rgba(53, 72, 91, 0.06);
    }
    .action-card strong,
    .disabled-card strong {
      display: block;
      font-size: 22px;
      margin-bottom: 8px;
    }
    .action-card span,
    .disabled-card span {
      color: var(--muted);
      line-height: 1.5;
      font-size: 15px;
    }
    .action-card.action-labels { background: var(--labels); }
    .action-card.action-envelopes { background: var(--envelopes); }
    .action-card.action-email { background: var(--email); }
    .action-card:hover { transform: translateY(-1px); }
    .disabled-card {
      background: #f5f7fa;
      color: var(--muted);
    }
    .action-form { gap: 14px; }
    .form-grid {
      display: grid;
      gap: 12px;
      grid-template-columns: repeat(2, minmax(0, 1fr));
    }
    .select-label {
      display: grid;
      gap: 6px;
      font-size: 13px;
      font-weight: 700;
      color: var(--ink);
    }
    .select-label select {
      width: 100%;
      border: 1px solid var(--line);
      border-radius: 10px;
      padding: 10px 12px;
      font: inherit;
      color: var(--ink);
      background: #fff;
    }
    .inline-action {
      align-self: flex-start;
      appearance: none;
      border: 0;
      border-radius: 999px;
      padding: 12px 18px;
      font: inherit;
      font-weight: 700;
      cursor: pointer;
      color: #fff;
      background: linear-gradient(135deg, var(--accent) 0%, var(--accent-dark) 100%);
      box-shadow: 0 10px 24px rgba(80, 158, 227, 0.22);
    }
    .footer-actions {
      margin-top: 22px;
      display: flex;
      gap: 12px;
      flex-wrap: wrap;
    }
    .close-button {
      display: inline-flex;
      align-items: center;
      justify-content: center;
      padding: 12px 18px;
      border-radius: 999px;
      border: 1px solid var(--line);
      background: var(--button-soft);
      color: var(--ink);
      font: inherit;
      font-weight: 700;
      cursor: pointer;
    }
    @media (max-width: 720px) {
      body { padding: 14px; }
      .hero { padding: 18px; }
      h1 { font-size: 28px; }
      .form-grid { grid-template-columns: 1fr; }
    }
  </style>
</head>
<body>
  <div class="wrap">${body}</div>
</body>
</html>`;
return [{ json: { html, response_code: hasBatch ? 200 : Number(source.response_code || 400) } }];
